```typescript
import * as QuickActions from 'expo-quick-actions';

const updateQuickActions = (cartItemsCount: number) => {
  if (cartItemsCount > 0) {
    QuickActions.setItems([{
      title: `Panier (${cartItemsCount} article)`,
      icon: 'shopping-cart',
      id: 'cart',
      params: { screen: 'Cart' }
    }]);
  } else {
    QuickActions.clearItems();
  }
};

// Dans le composant racine
QuickActions.addListener(({ id }) => {
  if (id === 'cart') navigation.navigate('Cart');
});
```

