const updateWidget = async (cartData: CartData) => {
  if (Platform.OS === 'ios') {
    await AppGroup.setItemAsync('cart', JSON.stringify(cartData), 'group.app.panier');
    await WidgetCenter.reloadAllTimelines();
  } else if (Platform.OS === 'android') {
    // Solution alternative : SharedPreferences via module natif ou expo-constants
    await SharedPreferences.setString('widget_cart', JSON.stringify(cartData));
  }
};
